    def test_p2_manifest_chain_preflight_generate_api_writes_safe_report(self):
        import json
        from http.client import HTTPConnection
        from http.server import HTTPServer
        from threading import Thread

        from quant_core.audit_events import AuditEventStore
        from quant_core.api import QuantApiHandler

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp) / "data"
            root.mkdir(parents=True)
            p1_path = root / "p1-acceptance.json"
            replay_path = root / "p2-paper-replay.json"
            pre_live_path = root / "p2-pre-live-acceptance.json"
            readiness_path = root / "p2-readiness-acceptance.json"
            output_path = root / "p2-chain-preflight.json"
            p1_path.write_text(json.dumps(self._sample_p1_acceptance_manifest()), encoding="utf-8")
            replay_path.write_text(json.dumps(self._sample_p2_paper_replay_manifest()), encoding="utf-8")
            pre_live_path.write_text(json.dumps(self._sample_p2_pre_live_acceptance_manifest()), encoding="utf-8")
            audit_store = AuditEventStore(root / "audit_events.sqlite")

            class TestHandler(QuantApiHandler):
                p1_acceptance_report_path = p1_path
                p2_paper_replay_report_path = replay_path
                p2_pre_live_acceptance_report_path = pre_live_path
                p2_readiness_acceptance_report_path = readiness_path
                p2_manifest_chain_preflight_report_path = output_path
                audit_event_store = audit_store

            server = HTTPServer(("127.0.0.1", 0), TestHandler)
            thread = Thread(target=server.serve_forever, daemon=True)
            thread.start()
            connection = HTTPConnection(server.server_address[0], server.server_address[1], timeout=5)
            try:
                connection.request("POST", "/api/p2/manifest-chain/preflight")
                response = connection.getresponse()
                payload = json.loads(response.read().decode("utf-8"))
                output_exists = output_path.exists()
                connection.request("GET", "/api/p2/manifest-chain/preflight/latest")
                latest_response = connection.getresponse()
                latest_payload = json.loads(latest_response.read().decode("utf-8"))
                audit_event_id = str(payload["auditEvent"]["eventId"])
                stored_event = audit_store.get(audit_event_id)
            finally:
                connection.close()
                server.shutdown()
                thread.join(timeout=5)
                server.server_close()

        self.assertEqual(response.status, 201)
        self.assertEqual(payload["status"], "preflight_generated")
        self.assertEqual(payload["preflight"]["status"], "blocked")
        self.assertEqual(payload["preflight"]["validStageCount"], 3)
        self.assertEqual(payload["preflight"]["nextAction"], "run-p2-readiness")
        self.assertTrue(output_exists)
        self.assertFalse(payload["preflight"]["orderSubmissionEnabled"])
        self.assertFalse(payload["preflight"]["liveTradingAllowed"])
        self.assertFalse(payload["preflight"]["liveOrderSubmitted"])
        self.assertFalse(payload["preflight"]["routeExecuted"])
        self.assertTrue(payload["preflight"]["liveBlockedBoundary"])
        self.assertEqual(payload["auditEvent"]["eventType"], "p2_manifest_chain_preflight")
        self.assertEqual(payload["auditEvent"]["stage"], "p2")
        self.assertEqual(payload["auditEvent"]["metadata"]["preflightStatus"], "blocked")
        self.assertEqual(payload["auditEvent"]["metadata"]["validStageCount"], 3)
        self.assertEqual(payload["auditEvent"]["metadata"]["totalStageCount"], 4)
        self.assertEqual(payload["auditEvent"]["metadata"]["nextAction"], "run-p2-readiness")
        self.assertFalse(payload["auditEvent"]["metadata"]["orderSubmissionEnabled"])
        self.assertFalse(payload["auditEvent"]["metadata"]["liveTradingAllowed"])
        self.assertFalse(payload["auditEvent"]["metadata"]["liveOrderSubmitted"])
        self.assertFalse(payload["auditEvent"]["metadata"]["routeExecuted"])
        self.assertIsNotNone(stored_event)
        self.assertEqual(stored_event.event_type, "p2_manifest_chain_preflight")
        self.assertEqual(latest_response.status, 200)
        self.assertEqual(latest_payload["preflight"]["status"], "blocked")
        self.assertEqual(latest_payload["preflight"]["validStageCount"], 3)

    def test_docker_smoke_cli_validates_p0_acceptance_report_without_compose(self):
        import contextlib
        import io

        docker_smoke = self._load_docker_smoke_module()
        manifest = docker_smoke.build_p0_acceptance_manifest(
            base_url="http://aiqt.local",
            import_base_url=None,
            market="ashare",
            symbol="600000",
            timeframe="1d",
            run_id="run-smoke",
            summaries=[
                "p0 pipeline run=run-smoke",
                "p0 ai-review run=run-smoke mode=local_evidence_review",
                "p0 paper-simulation run=run-smoke liveBlocked=True",
                "p0 export run=run-smoke completeness=9/9 auditEvents=1 liveBlocked=True",
            ],
        )

        with tempfile.TemporaryDirectory() as tmp:
            report_path = Path(tmp) / "p0-acceptance.json"
            docker_smoke.write_p0_acceptance_report(report_path, manifest)

            def fail_run_smoke(*args, **kwargs):
                raise AssertionError("run_smoke should not be called in report validation mode")

            original_run_smoke = docker_smoke.run_smoke
            docker_smoke.run_smoke = fail_run_smoke
            output = io.StringIO()
            try:
                with contextlib.redirect_stdout(output):
                    exit_code = docker_smoke.main(["--validate-p0-acceptance-report", str(report_path)])
            finally:
                docker_smoke.run_smoke = original_run_smoke

        self.assertEqual(exit_code, 0)
        self.assertIn("p0 acceptance manifest run=run-smoke checks=4 liveBlocked=True", output.getvalue())

    def test_docker_smoke_p0_acceptance_runs_paper_only_sequence(self):
        docker_smoke = self._load_docker_smoke_module()
        posts = []

        def fake_post_json(url, payload, timeout_seconds):
            posts.append((url, payload, timeout_seconds))
            if url.endswith("/api/p0/pipeline"):
                return {
                    "status": "audited_run_created",
                    "runId": "run-smoke",
                    "strategyRevisionId": "strategy-smoke",
                    "dataSnapshotId": "data-smoke",
                    "metrics": {"totalReturnPct": 1.2, "maxDrawdownPct": 0.4, "tradeCount": 1},
                    "paperOnly": True,
                    "liveTradingAllowed": False,
                }
            if url.endswith("/api/p0/ai-reviews"):
                return {
                    "status": "ai_review_saved",
                    "mode": "local_evidence_review",
                    "aiReview": {"aiReviewId": "ai-review-smoke"},
                    "paperOnly": True,
                    "liveTradingAllowed": False,
                    "directTradingInstructionBlocked": True,
                }
            if url.endswith("/api/p0/paper-simulations"):
                return {
                    "status": "paper_simulation_created",
                    "paperOnly": True,
                    "liveTradingAllowed": False,
                    "liveOrderSubmitted": False,
                    "routeExecuted": False,
                    "auditEvent": {"eventType": "p0_paper_simulation"},
                    "exportReadiness": {"ready": True},
                }
            raise AssertionError(f"Unexpected POST URL: {url}")

        def fake_request_json(url, timeout_seconds):
            self.assertTrue(url.endswith("/api/research/runs/run-smoke/export"))
            return {
                "export": {
                    "manifest": {"runId": "run-smoke", "artifactCounts": {"auditEvents": 1}},
                    "auditEvents": [{"eventType": "p0_paper_simulation"}],
                    "p0PackageCompleteness": {
                        "ready": True,
                        "status": "complete",
                        "passed": 9,
                        "total": 9,
                        "paperOnly": True,
                        "liveTradingAllowed": False,
                        "liveBlockedBoundary": True,
                    },
                }
            }

        original_post_json = docker_smoke.post_json
        original_request_json = docker_smoke.request_json
        docker_smoke.post_json = fake_post_json
        docker_smoke.request_json = fake_request_json
        try:
            summaries = docker_smoke.run_p0_acceptance(
                "http://aiqt.local",
                timeout_seconds=5,
                market="ashare",
                symbol="600000",
                timeframe="1d",
                quantity=2100,
            )
        finally:
            docker_smoke.post_json = original_post_json
            docker_smoke.request_json = original_request_json

        self.assertEqual(
            [url.removeprefix("http://aiqt.local") for url, _, _ in posts],
            ["/api/p0/pipeline", "/api/p0/ai-reviews", "/api/p0/paper-simulations"],
        )
        self.assertEqual(posts[2][1]["route"], "paper")
        self.assertFalse(posts[2][1]["liveTradingAllowed"])
        self.assertFalse(posts[2][1]["orderSubmitted"])
        self.assertIn("p0 pipeline run=run-smoke", summaries)
        self.assertIn("p0 export run=run-smoke completeness=9/9 auditEvents=1 liveBlocked=True", summaries)

    def test_docker_smoke_p0_acceptance_can_import_and_revalidate_export(self):
        import json

        docker_smoke = self._load_docker_smoke_module()
        posts = []
        exports = []

        source_export = {
            "manifest": {"runId": "run-smoke", "artifactCounts": {"auditEvents": 1}},
            "auditEvents": [{"eventType": "p0_paper_simulation"}],
            "paperExecutions": [{"executionId": "paper-smoke", "runId": "run-smoke"}],
            "aiReviewRuns": [{"aiReviewId": "ai-review-smoke", "runId": "run-smoke"}],
            "p0PackageCompleteness": {
                "ready": True,
                "status": "complete",
                "passed": 9,
                "total": 9,
                "paperOnly": True,
                "liveTradingAllowed": False,
                "liveBlockedBoundary": True,
            },
        }

        def fake_post_json(url, payload, timeout_seconds):
            posts.append((url, payload, timeout_seconds))
            if url.endswith("/api/p0/pipeline"):
                return {
                    "status": "audited_run_created",
                    "runId": "run-smoke",
                    "metrics": {"tradeCount": 1},
                    "paperOnly": True,
                    "liveTradingAllowed": False,
                }
            if url.endswith("/api/p0/ai-reviews"):
                return {
                    "status": "ai_review_saved",
                    "mode": "local_evidence_review",
                    "aiReview": {"aiReviewId": "ai-review-smoke"},
                    "paperOnly": True,
                    "liveTradingAllowed": False,
                    "directTradingInstructionBlocked": True,
                }
            if url.endswith("/api/p0/paper-simulations"):
                return {
                    "status": "paper_simulation_created",
                    "paperOnly": True,
                    "liveTradingAllowed": False,
                    "liveOrderSubmitted": False,
                    "routeExecuted": False,
                    "auditEvent": {"eventType": "p0_paper_simulation"},
                    "exportReadiness": {"ready": True},
                }
            if url.endswith("/api/research/runs/import"):
                self.assertEqual(url, "http://clean.local/api/research/runs/import")
                self.assertEqual(payload, source_export)
                return {
                    "run": {
                        "runId": "run-smoke",
                        "executionMode": "paper_only",
                        "strategyRevision": "strategy-smoke",
                        "dataSnapshot": {"bars": [{"timestamp": "2026-06-23T08:00:00+00:00"}]},
                    },
                    "undoToken": "import-undo-smoke",
                    "undo": {"runId": "run-smoke"},
                }
            raise AssertionError(f"Unexpected POST URL: {url}")

        def fake_request_json(url, timeout_seconds):
            exports.append(url)
            if url == "http://aiqt.local/api/research/runs/run-smoke/export":
                return {"export": source_export}
            if url == "http://clean.local/api/research/runs/run-smoke/export":
                return {"export": source_export}
            raise AssertionError(f"Unexpected GET URL: {url}")

        original_post_json = docker_smoke.post_json
        original_request_json = docker_smoke.request_json
        docker_smoke.post_json = fake_post_json
        docker_smoke.request_json = fake_request_json
        try:
            with tempfile.TemporaryDirectory() as tmp:
                report_path = Path(tmp) / "p0-acceptance.json"
                summaries = docker_smoke.run_p0_acceptance(
                    "http://aiqt.local",
                    timeout_seconds=5,
                    market="ashare",
                    symbol="600000",
                    timeframe="1d",
                    quantity=2100,
                    import_check=True,
                    import_base_url="http://clean.local",
                    report_path=report_path,
                )
                report_payload = json.loads(report_path.read_text(encoding="utf-8"))
        finally:
            docker_smoke.post_json = original_post_json
            docker_smoke.request_json = original_request_json

        self.assertIn("http://clean.local/api/research/runs/import", [url for url, _, _ in posts])
        self.assertEqual(
            exports,
            [
                "http://aiqt.local/api/research/runs/run-smoke/export",
                "http://clean.local/api/research/runs/run-smoke/export",
            ],
        )
        self.assertIn("p0 import run=run-smoke undo=import-undo-smoke", summaries)
        self.assertIn("p0 imported-export run=run-smoke completeness=9/9 auditEvents=1 liveBlocked=True", summaries)
        self.assertEqual(report_payload["status"], "passed")
        self.assertEqual(report_payload["runId"], "run-smoke")
        self.assertIn("imported-export", [check["id"] for check in report_payload["checks"]])

    def test_docker_smoke_builds_and_validates_p1_acceptance_manifest(self):
        docker_smoke = self._load_docker_smoke_module()

        manifest = docker_smoke.build_p1_acceptance_manifest(
            base_url="http://aiqt.local",
            import_base_url="http://clean.local",
            timeframe="1d",
            run_id="run-p1-smoke",
            watchlist_refresh_run_id="cache-refresh-p1",
            queued_market="ashare",
            queued_symbol="600000",
            watchlist=[
                {"market": "ashare", "symbol": "600000", "name": "浦发银行"},
                {"market": "ashare", "symbol": "000300", "name": "沪深300"},
                {"market": "us", "symbol": "AAPL", "name": "Apple"},
            ],
            summaries=[
                "p1 workspace watchlist=3 selected=600000",
                "p1 watchlist-refresh run=cache-refresh-p1 symbols=3 refreshed=3 queued=600000",
                "p1 queue-pipeline run=run-p1-smoke symbol=600000 refresh=cache-refresh-p1",
                "p1 ai-review run=run-p1-smoke mode=local_evidence_review",
                "p1 paper-simulation run=run-p1-smoke liveBlocked=True",
                "p1 export run=run-p1-smoke refresh=cache-refresh-p1 liveBlocked=True",
                "p1 import run=run-p1-smoke undo=import-undo-p1",
                "p1 imported-export run=run-p1-smoke refresh=cache-refresh-p1 liveBlocked=True",
            ],
        )

        self.assertEqual(manifest["kind"], "aiqt.p1AcceptanceManifest")
        self.assertEqual(manifest["schemaVersion"], 1)
        self.assertEqual(manifest["status"], "passed")
        self.assertEqual(manifest["runId"], "run-p1-smoke")
        self.assertEqual(manifest["watchlistRefreshRunId"], "cache-refresh-p1")
        self.assertEqual(manifest["queuedSymbol"], "600000")
        self.assertEqual(manifest["watchlistCount"], 3)
        self.assertTrue(manifest["paperOnly"])
        self.assertFalse(manifest["liveTradingAllowed"])
        self.assertTrue(manifest["liveBlockedBoundary"])
        self.assertEqual(
            [check["id"] for check in manifest["checks"]],
            [
                "workspace",
                "watchlist-refresh",
                "queue-pipeline",
                "ai-review",
                "paper-simulation",
                "export",
                "import",
                "imported-export",
            ],
        )
        self.assertEqual(
            docker_smoke.validate_p1_acceptance_manifest(manifest),
            "p1 acceptance manifest run=run-p1-smoke watchlist=3 checks=8 liveBlocked=True",
        )

        unsafe_manifest = dict(manifest)
        unsafe_manifest["liveTradingAllowed"] = True
        with self.assertRaisesRegex(RuntimeError, "Invalid P1 acceptance manifest"):
            docker_smoke.validate_p1_acceptance_manifest(unsafe_manifest)

        missing_refresh_manifest = dict(manifest)
        missing_refresh_manifest["checks"] = [
            check for check in manifest["checks"] if check["id"] != "watchlist-refresh"
        ]
        with self.assertRaisesRegex(RuntimeError, "Invalid P1 acceptance manifest"):
            docker_smoke.validate_p1_acceptance_manifest(missing_refresh_manifest)

