        self.assertEqual(latest[0].strategy_config["entryConditions"][0]["params"], {"window": 20})
        self.assertEqual(latest[0].strategy_config["risk"]["positionPct"], 0.8)
        self.assertIn("SMA trend demo", latest[0].ai_report["summary"])
